import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"故宫博物院","description":"","frontmatter":{},"headers":[],"relativePath":"museums/palace-museum.md","filePath":"museums/palace-museum.md","lastUpdated":null}'),d={name:"museums/palace-museum.md"};function n(s,t,i,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="故宫博物院" tabindex="-1">故宫博物院 <a class="header-anchor" href="#故宫博物院" aria-label="Permalink to &quot;故宫博物院&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1508804185872-d7badad00f7d?w=1200" alt="故宫博物院"></p><blockquote><p>&quot;一座紫禁城，半部中国史。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>故宫博物院，即紫禁城，是明清两代的皇家宫殿，也是中国最大的古代文化艺术博物馆。故宫博物院成立于1925年10月10日，是在明清皇宫及其收藏基础上建立起来的大型综合性博物馆。</p><p>作为中国博物馆界的翘楚，故宫博物院收藏文物超过186万件（套），涵盖绘画、书法、碑帖、铜器、金银器等多个门类。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:30-17:00（旺季），8:30-16:30（淡季），周一闭馆</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">旺季60元，淡季40元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线天安门东/西站</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">提前7天预约</td></tr></tbody></table><h2 id="馆藏珍品" tabindex="-1">馆藏珍品 <a class="header-anchor" href="#馆藏珍品" aria-label="Permalink to &quot;馆藏珍品&quot;">​</a></h2><h3 id="书画之宝" tabindex="-1">书画之宝 <a class="header-anchor" href="#书画之宝" aria-label="Permalink to &quot;书画之宝&quot;">​</a></h3><p>故宫博物院书画收藏达15万余件，几乎涵盖了中国书画发展的各个历史时期。</p><table tabindex="0"><thead><tr><th style="text-align:left;">藏品</th><th style="text-align:center;">朝代</th><th style="text-align:left;">价值</th></tr></thead><tbody><tr><td style="text-align:left;">《清明上河图》</td><td style="text-align:center;">北宋</td><td style="text-align:left;">张择端传世名作</td></tr><tr><td style="text-align:left;">《千里江山图》</td><td style="text-align:center;">北宋</td><td style="text-align:left;">王希孟青绿山水</td></tr><tr><td style="text-align:left;">《韩熙载夜宴图》</td><td style="text-align:center;">五代</td><td style="text-align:left;">顾闳中人物画杰作</td></tr></tbody></table><p><img src="https://images.unsplash.com/photo-1516961642265-531546e84af2?w=800" alt="清明上河图"></p><h3 id="青铜之宝" tabindex="-1">青铜之宝 <a class="header-anchor" href="#青铜之宝" aria-label="Permalink to &quot;青铜之宝&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">藏品</th><th style="text-align:center;">朝代</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;">后母戊鼎</td><td style="text-align:center;">商代</td><td style="text-align:left;">世界最大青铜器</td></tr><tr><td style="text-align:left;">毛公鼎</td><td style="text-align:center;">西周</td><td style="text-align:left;">铭文最长的青铜器</td></tr></tbody></table><h3 id="陶瓷之宝" tabindex="-1">陶瓷之宝 <a class="header-anchor" href="#陶瓷之宝" aria-label="Permalink to &quot;陶瓷之宝&quot;">​</a></h3><p>陶瓷藏品超过37万件，是世界上收藏中国陶瓷最多的博物馆。</p><table tabindex="0"><thead><tr><th style="text-align:left;">窑口</th><th style="text-align:left;">代表作品</th></tr></thead><tbody><tr><td style="text-align:left;">汝窑</td><td style="text-align:left;">天青釉碗</td></tr><tr><td style="text-align:left;">官窑</td><td style="text-align:left;">青釉瓷</td></tr><tr><td style="text-align:left;">哥窑</td><td style="text-align:left;">金丝铁线</td></tr></tbody></table><h2 id="专题展馆" tabindex="-1">专题展馆 <a class="header-anchor" href="#专题展馆" aria-label="Permalink to &quot;专题展馆&quot;">​</a></h2><h3 id="钟表馆-奉先殿" tabindex="-1">钟表馆（奉先殿） <a class="header-anchor" href="#钟表馆-奉先殿" aria-label="Permalink to &quot;钟表馆（奉先殿）&quot;">​</a></h3><p>收藏中外钟表200余件，展现了18-20世纪世界钟表制造的顶尖水平。</p><h3 id="珍宝馆-宁寿宫区" tabindex="-1">珍宝馆（宁寿宫区） <a class="header-anchor" href="#珍宝馆-宁寿宫区" aria-label="Permalink to &quot;珍宝馆（宁寿宫区）&quot;">​</a></h3><p>展示清代宫廷制作及收藏的珍贵文物，包括金器、银器、玉器、宝石等。</p><p><img src="https://images.unsplash.com/photo-1608371945643-31172d590525?w=800" alt="珍宝"></p><h3 id="石鼓馆-宁寿宫" tabindex="-1">石鼓馆（宁寿宫） <a class="header-anchor" href="#石鼓馆-宁寿宫" aria-label="Permalink to &quot;石鼓馆（宁寿宫）&quot;">​</a></h3><p>收藏被誉为&quot;石刻之祖&quot;的十面先秦石鼓。</p><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="文物南迁" tabindex="-1">文物南迁 <a class="header-anchor" href="#文物南迁" aria-label="Permalink to &quot;文物南迁&quot;">​</a></h3><p>1933年，为躲避日本侵略者的掠夺，故宫13427箱珍贵文物开始分批南迁。这次历时十余年的文物大迁徙，辗转万里，无一损毁丢失，创造了世界文物史上的奇迹。</p><h3 id="故宫跑" tabindex="-1">&quot;故宫跑&quot; <a class="header-anchor" href="#故宫跑" aria-label="Permalink to &quot;&quot;故宫跑&quot;&quot;">​</a></h3><p>2015年《清明上河图》展出时，观众为第一时间观赏，清晨就在午门外排队，开门后以百米冲刺的速度冲向展厅，形成独特的&quot;故宫跑&quot;文化现象。</p><h3 id="故宫猫" tabindex="-1">故宫猫 <a class="header-anchor" href="#故宫猫" aria-label="Permalink to &quot;故宫猫&quot;">​</a></h3><p>故宫里生活着百余只&quot;御猫&quot;，它们大多是当年皇家饲养的猫的后代。如今它们已成为网红，拥有自己的粉丝群。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐参观路线" tabindex="-1">推荐参观路线 <a class="header-anchor" href="#推荐参观路线" aria-label="Permalink to &quot;推荐参观路线&quot;">​</a></h3><p><strong>精华半日游（4小时）</strong>： 午门 → 太和殿 → 中和殿 → 保和殿 → 乾清宫 → 交泰殿 → 坤宁宫 → 御花园 → 神武门</p><p><strong>深度一日游（6-8小时）</strong>： 午门 → 武英殿 → 太和殿 → 中和殿 → 保和殿 → 钟表馆 → 珍宝馆 → 东六宫 → 乾清宫 → 交泰殿 → 坤宁宫 → 御花园 → 西六宫 → 神武门</p><h3 id="预约须知" tabindex="-1">预约须知 <a class="header-anchor" href="#预约须知" aria-label="Permalink to &quot;预约须知&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前7天在官网或微信公众号预约</li><li><strong>实名购票</strong>：需持身份证原件入馆</li><li><strong>限流措施</strong>：每日限流8万人次</li><li><strong>周一闭馆</strong>：法定节假日除外</li></ol><h3 id="参观建议" tabindex="-1">参观建议 <a class="header-anchor" href="#参观建议" aria-label="Permalink to &quot;参观建议&quot;">​</a></h3><ol><li><strong>早到为宜</strong>：8:30开门即入，避开人流高峰</li><li><strong>中轴线先行</strong>：先参观中轴线主要建筑</li><li><strong>租借讲解</strong>：建议租借语音导览</li><li><strong>注意体力</strong>：故宫面积巨大，穿舒适的鞋子</li></ol><h2 id="交通指南" tabindex="-1">交通指南 <a class="header-anchor" href="#交通指南" aria-label="Permalink to &quot;交通指南&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">入口</th><th style="text-align:left;">交通方式</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>午门（南门）</strong></td><td style="text-align:left;">地铁1号线天安门东/西站</td></tr><tr><td style="text-align:left;"><strong>神武门（北门）</strong></td><td style="text-align:left;">公交101、103、109路</td></tr><tr><td style="text-align:left;"><strong>东华门（东门）</strong></td><td style="text-align:left;">公交2、82路</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">景山公园</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">俯瞰故宫全景</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">皇家园林</td></tr><tr><td style="text-align:left;">天安门广场</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">世界最大广场</td></tr></tbody></table><hr><p><strong>💡 Tips</strong>：故宫是北京的灵魂所在，建议预留充足时间，用心感受这座承载了六百年皇家记忆的文化殿堂。</p>',47)])])}const u=e(d,[["render",n]]);export{f as __pageData,u as default};
